import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);
  const [statusFilter, setStatusFilter] = useState("ALL");
  const [severityFilter, setSeverityFilter] = useState("ALL");
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  // fetch data
  const fetchData = async () => {
    try {
      setLoading(true);
      const res = await fetch("http://localhost:8000/incidents");
      const data = await res.json();
      setIncidents(data);
    } catch {
      alert("Failed to fetch incidents");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  // KPIs
  const total = incidents.length;
  const open = incidents.filter(i => i.status === "OPEN").length;
  const closed = incidents.filter(i => i.status === "CLOSED").length;

  // filtering
  const filtered = incidents
    .filter(i => statusFilter === "ALL" || i.status === statusFilter)
    .filter(i => severityFilter === "ALL" || i.severity === severityFilter)
    .filter(i =>
      i.component_id.toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => b.id - a.id);

  return (
    <div style={page}>

      {/* HEADER */}
      <div style={header}>
        <h2 style={{ margin: 0 }}>IT Incident Dashboard</h2>
        <span style={{ color: "#888" }}>Live Monitoring</span>
      </div>

      {/* KPI */}
      <div style={kpiContainer}>
        <KPI label="Total" value={total} color="#2f6fed" />
        <KPI label="Open" value={open} color="#ff4d4f" />
        <KPI label="Closed" value={closed} color="#28a745" />
      </div>

      {/* CONTROLS */}
      <div style={controls}>
        <input
          placeholder="Search component..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={input}
        />

        <select onChange={(e) => setSeverityFilter(e.target.value)}>
          <option value="ALL">All Priorities</option>
          <option value="P0">P0</option>
          <option value="P1">P1</option>
        </select>

        <select onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="ALL">All Statuses</option>
          <option value="OPEN">Open ({open})</option>
          <option value="CLOSED">Closed ({closed})</option>
        </select>

        <button onClick={() => {
          setStatusFilter("ALL");
          setSeverityFilter("ALL");
          setSearch("");
        }}>
          Clear
        </button>
      </div>

      {/* LOADING */}
      {loading && <p style={center}>Loading incidents...</p>}

      {/* EMPTY STATE */}
      {!loading && filtered.length === 0 && (
        <div style={empty}>
          <h3>No incidents found</h3>
          <p>Try adjusting filters or search</p>
        </div>
      )}

      {/* CARDS */}
      <div style={grid}>
        {filtered.map((i) => (
          <div key={i.id} style={card}>

            <div style={cardHeader}>
              <h3>{i.component_id}</h3>
              <span style={statusBadge(i.status)}>{i.status}</span>
            </div>

            <p style={subText}>Incident #{i.id}</p>

            <div style={badgeRow}>
              <span style={severityBadge(i.severity)}>
                {i.severity}
              </span>

              <span style={signalBadge}>
                {i.signal_count} signals
              </span>
            </div>

            <p style={time}>
              {new Date(i.start_time).toLocaleString()}
            </p>

            <Link to={`/incident/${i.id}`}>
              <button style={viewBtn}>View Details →</button>
            </Link>

          </div>
        ))}
      </div>
    </div>
  );
}

// KPI component
function KPI({ label, value, color }) {
  return (
    <div style={{ ...kpi, borderTop: `4px solid ${color}` }}>
      <p>{label}</p>
      <h2>{value}</h2>
    </div>
  );
}

// STYLES

const page = {
  background: "#f4f6f8",
  minHeight: "100vh",
  padding: "25px",
  fontFamily: "Segoe UI"
};

const header = {
  position: "sticky",
  top: 0,
  background: "#f4f6f8",
  paddingBottom: "10px",
  marginBottom: "20px",
  display: "flex",
  justifyContent: "space-between"
};

const kpiContainer = {
  display: "flex",
  gap: "15px",
  marginBottom: "20px"
};

const kpi = {
  background: "#fff",
  padding: "12px",
  borderRadius: "10px",
  width: "120px",
  boxShadow: "0 2px 6px rgba(0,0,0,0.05)"
};

const controls = {
  display: "flex",
  gap: "10px",
  marginBottom: "20px"
};

const input = {
  padding: "6px",
  borderRadius: "6px",
  border: "1px solid #ccc"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
  gap: "20px"
};

const card = {
  background: "#fff",
  padding: "18px",
  borderRadius: "12px",
  boxShadow: "0 3px 10px rgba(0,0,0,0.07)",
  transition: "0.2s",
};

const cardHeader = {
  display: "flex",
  justifyContent: "space-between"
};

const subText = { color: "#666" };

const badgeRow = {
  display: "flex",
  justifyContent: "space-between"
};

const severityBadge = (sev) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  background: sev === "P0" ? "#ffe5e5" : "#fff3cd"
});

const statusBadge = (status) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  background: status === "OPEN" ? "#e6f0ff" : "#e6ffe6"
});

const signalBadge = { fontSize: "12px" };

const time = { fontSize: "12px", color: "#888" };

const viewBtn = {
  marginTop: "10px",
  padding: "6px 10px",
  background: "#2f6fed",
  color: "#fff",
  border: "none",
  borderRadius: "6px",
  cursor: "pointer"
};

const empty = {
  textAlign: "center",
  padding: "40px",
  background: "#fff",
  borderRadius: "10px"
};

const center = { textAlign: "center" };
